import{_ as o,o as a,c as t,a3 as r}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"XiHan.Framework.Bot.Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/bot-telegram.md","filePath":"cosmos/framework/packages/bot-telegram.md","lastUpdated":1783216089000}'),d={name:"cosmos/framework/packages/bot-telegram.md"};function i(l,e,s,c,n,h){return a(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="xihan-framework-bot-telegram" tabindex="-1">XiHan.Framework.Bot.Telegram <a class="header-anchor" href="#xihan-framework-bot-telegram" aria-label="Permalink to &quot;XiHan.Framework.Bot.Telegram&quot;">​</a></h1><blockquote><p>Telegram 机器人：单发通道 + 多机器人交互平台</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Bot.Telegram</code></li><li><strong>模块类</strong>：<code>XiHanBotTelegramModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这个包为 <code>XiHan.Framework.Bot</code> 提供 Telegram 通道，基于官方 <strong>Telegram.Bot</strong> SDK。它有两层能力：一是作为标准 <code>IBotProvider</code> 接入统一 Bot 调度（用于纯通知发送）；二是一套更完整的「多机器人交互平台」，支持 Webhook / 长轮询双模传输、命令 / 回调 / 消息路由、会话状态与出站审计，用于构建可交互的 Telegram 机器人。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>只想往 Telegram 发通知：通过统一 <code>IBotClient</code> 走 <code>TelegramBotProvider</code></li><li>想构建可交互机器人：处理用户命令、内联按钮回调、多轮会话，可同时托管多个机器人实例</li><li>需要 Webhook 接收更新（ASP.NET Core 端点）或长轮询两种接入方式</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Bot.Telegram</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanBotTelegramModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块依赖 <code>XiHanBotModule</code>，在 <code>ConfigureServices</code> 里同时注册单发通道（<code>AddXiHanBotTelegram</code>）与多机器人平台（<code>AddXiHanBotTelegramPlatform</code>）。单发通道在 <code>BotBuilder</code> 上用 <code>UseTelegram(configure)</code> 启用；平台默认不启用，由配置节 <code>XiHan:Bot:Telegram:Platform</code> 或应用层 store 开启。本包依赖 <code>Microsoft.AspNetCore.App</code>（Webhook 端点需要）。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>单发通道</strong>：<code>TelegramBotProvider</code> 实现 <code>IBotProvider</code>，接入统一 Bot 调度用于通知发送</li><li><strong>主动发送门面</strong>：<code>ITelegramNotifier</code> / <code>TelegramNotifier</code> 按机器人名发文本 / Markdown / 图片 / 文件，可编辑消息与内联键盘，内建 429/5xx/超时重试退避与出站审计</li><li><strong>多机器人托管</strong>：<code>TelegramBotManager</code> / <code>BotRegistry</code> / <code>TelegramBotHostedService</code> 托管多个机器人实例，支持双模传输</li><li><strong>更新分发与路由</strong>：<code>TelegramUpdateDispatcher</code> 配合命令 / 回调 / 消息 / 内联查询 / 回复各类路由器分发更新</li><li><strong>处理器扩展点</strong>：<code>IBotCommandHandler</code> / <code>IBotCallbackHandler</code> / <code>IBotMessageHandler</code> 等接口 + <code>[BotCommand]</code> / <code>[BotCallback]</code> 特性声明处理器</li><li><strong>会话状态与去重</strong>：<code>IConversationStateStore</code>（多轮会话状态）、<code>ITelegramUpdateDeduplicator</code>（更新去重）、<code>ITelegramMessageAuditStore</code>（消息审计），均有内存默认实现，应用层可换 store</li><li><strong>Webhook 接入</strong>：<code>TelegramBotWebhookMiddleware</code> + 应用构建器扩展映射 Webhook 端点</li><li><strong>可插拔配置</strong>：<code>ITelegramConfigStore</code> / <code>ITelegramBotConfigStore</code> / <code>ITelegramBotSettingsStore</code> 抽象配置来源，默认读选项，应用层可换 DB</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>TelegramBotProvider</code></td><td>Telegram 单发通道提供者（<code>IBotProvider</code> 实现）</td></tr><tr><td><code>ITelegramNotifier</code> / <code>TelegramNotifier</code></td><td>主动发送门面（文本 / Markdown / 图片 / 文件 / 编辑）</td></tr><tr><td><code>TelegramBotManager</code> / <code>BotRegistry</code></td><td>多机器人托管与注册表</td></tr><tr><td><code>TelegramBotHostedService</code></td><td>后台托管服务（启动 / 停止机器人实例）</td></tr><tr><td><code>TelegramUpdateDispatcher</code></td><td>更新分发（分派到各路由器）</td></tr><tr><td><code>IBotCommandHandler</code> / <code>IBotCallbackHandler</code> / <code>IBotMessageHandler</code></td><td>命令 / 回调 / 消息处理器扩展点</td></tr><tr><td><code>IConversationStateStore</code> / <code>ITelegramUpdateDeduplicator</code> / <code>ITelegramMessageAuditStore</code></td><td>会话状态 / 更新去重 / 消息审计（均有默认实现）</td></tr><tr><td><code>TelegramBotWebhookMiddleware</code></td><td>Webhook 接收中间件</td></tr><tr><td><code>TelegramBotPlatformOptions</code></td><td>平台选项（配置节 <code>XiHan:Bot:Telegram:Platform</code>）</td></tr><tr><td><code>TelegramOptions</code> / <code>ITelegramConfigStore</code></td><td>单发通道选项与配置来源</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./bot">XiHan.Framework.Bot</a>（核心抽象与调度）</li><li>第三方核心：<strong>Telegram.Bot</strong>（官方 SDK）+ <code>Microsoft.AspNetCore.App</code>（Webhook 端点）</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./bot">XiHan.Framework.Bot</a></li><li><a href="./bot-email">XiHan.Framework.Bot.Email</a> · <a href="./bot-sms">XiHan.Framework.Bot.Sms</a></li></ul>`,20)])])}const k=o(d,[["render",i]]);export{m as __pageData,k as default};
